windowclass.script:
			local _bHasData = false;

			function onInit()
				self.refresh();
			end
			function refresh()
				_bHasData = (list.getWindowCount() ~= 0);
				status.setVisible(_bHasData);
				status.setValue(1);
				list.setVisible(false);
			end
			function toggleList()
				if not _bHasData then
					return;
				end
				if status.getValue() == 0 then
					status.setValue(1);
					list.setVisible(false);
				else
					status.setValue(0);
					list.setVisible(true);
				end
			end

header_content_framed_rowshade.script:
function onClickDown(button, x, y)
	return true;
end
function onClickRelease(button, x, y)
	window.toggleList();
	return true;
end

windowclass.script:
function activate()
	RMTableManager.browseTable(getDatabaseNode());
end
function drag(button, x, y, dragdata)
	local customData = {};
	if not dragdata.getCustomData() then
		local node = getDatabaseNode();
		dragdata.setType("string")
		dragdata.setStringData(Name.getValue()); 
		customData.type = "RMCTable";
		customData.tableID = Id.getValue();
		customData.tableName = Name.getValue();
		dragdata.setCustomData(customData);
	end
	return true;
end

buttonc_listitem_left.script:
function activate()
	window.activate();
end
function onButtonPress()
	window.activate();
	return true;
end
function onDragStart(...)
	return window.drag(...);
end

windowclass.script:
function onInit()
	local node = getDatabaseNode();
	local nDefaultWidth = DB.getValue(node, "placement.size.width");
	local nDefaultHeight = DB.getValue(node, "placement.size.height");
	if nDefaultWidth and nDefaultHeight then
		setSize(nDefaultWidth, nDefaultHeight);
	end
end
